import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { createGame, createSudoku } from '../../../domain/index.js';

const EMPTY_GRID = Array.from({ length: 9 }, () => Array(9).fill(0));

function cloneGrid(grid) {
	return grid.map(row => [...row]);
}

let currentGame = createGame({ sudoku: createSudoku(EMPTY_GRID) });

function syncUserGrid(userGridStore) {
	userGridStore.set(currentGame.getSudoku().getGrid());
}

function createGrid() {
	const grid = writable(cloneGrid(EMPTY_GRID));

	return {
		subscribe: grid.subscribe,

		generate(difficulty) {
			const puzzle = generateSudoku(difficulty);
			grid.set(cloneGrid(puzzle));
			userGrid.loadPuzzle(puzzle);
		},

		decodeSencode(sencode) {
			const puzzle = decodeSencode(sencode);
			grid.set(cloneGrid(puzzle));
			userGrid.loadPuzzle(puzzle);
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

function createUserGrid() {
	const userGrid = writable(cloneGrid(EMPTY_GRID));

	return {
		subscribe: userGrid.subscribe,

		loadPuzzle(puzzle) {
			currentGame = createGame({ sudoku: createSudoku(puzzle) });
			syncUserGrid(userGrid);
		},

		guess(pos, value) {
			currentGame.guess({ row: pos.y, col: pos.x, value });
			syncUserGrid(userGrid);
		},

		undo() {
			currentGame.undo();
			syncUserGrid(userGrid);
		},

		redo() {
			currentGame.redo();
			syncUserGrid(userGrid);
		},

		canUndo() {
			return currentGame.canUndo();
		},

		canRedo() {
			return currentGame.canRedo();
		},

		getGame() {
			return currentGame;
		},

		applyHint(pos) {
			hints.useHint();
			const solvedSudoku = solveSudoku(currentGame.getSudoku().getGrid());
			currentGame.guess({ row: pos.y, col: pos.x, value: solvedSudoku[pos.y][pos.x] });
			syncUserGrid(userGrid);
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(userGrid, $userGrid => {
	return createSudoku($userGrid).getInvalidCellKeys();
}, []);
